"use client";

import React, { useEffect, useRef, useState } from "react";
import { cn } from "@/lib/utils";

export interface CosmicEyeProps {
  /** Primary eye color */
  color?: string;
  /** Secondary accent color */
  accentColor?: string;
  /** Intensity of the glow (0.5-3) */
  intensity?: number;
  /** Pupil size (0.2-1.0) */
  pupilSize?: number;
  /** Iris width (0.1-0.5) */
  irisWidth?: number;
  /** Outer glow intensity */
  glowIntensity?: number;
  /** Overall scale */
  scale?: number;
  /** Noise pattern scale */
  noiseScale?: number;
  /** How much the pupil follows cursor (0-2) */
  pupilFollow?: number;
  /** Animation speed */
  speed?: number;
  /** Additional className */
  className?: string;
}

// Deterministic hash-based pseudo-random
function seededRandom(n: number): number {
  const x = Math.sin(n * 9301 + 49297) % 1;
  return x - Math.floor(x);
}

const VERTEX_SHADER = `
attribute vec2 uv;
attribute vec2 position;
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = vec4(position, 0, 1);
}
`;

const FRAGMENT_SHADER = `
precision highp float;

uniform float uTime;
uniform float uAspect;
uniform vec2 uMouse;
uniform vec3 uColor;
uniform vec3 uAccentColor;
uniform float uIntensity;
uniform float uPupilSize;
uniform float uIrisWidth;
uniform float uGlowIntensity;
uniform float uScale;
uniform float uNoiseScale;
uniform float uPupilFollow;
uniform sampler2D uNoiseTex;

varying vec2 vUv;

// Polar coordinates helper
vec2 toPolar(vec2 p) {
  return vec2(length(p), atan(p.y, p.x));
}

// Smooth noise from texture
float sampleNoise(vec2 p) {
  return texture2D(uNoiseTex, fract(p * 0.5 + 0.5)).r;
}

// Fractal brownian motion with 4 octaves
float fbm(vec2 p) {
  float value = 0.0;
  float amplitude = 0.5;
  float frequency = 1.0;
  for (int i = 0; i < 4; i++) {
    value += amplitude * sampleNoise(p * frequency * uNoiseScale);
    frequency *= 2.17;
    amplitude *= 0.48;
  }
  return value;
}

void main() {
  // Center UVs and correct for aspect ratio
  vec2 uv = (vUv - 0.5) * 2.0;
  uv.x *= uAspect;
  uv /= uScale;

  // Pupil offset from mouse with clamped range
  vec2 pupilOffset = uMouse * uPupilFollow * 0.15;

  // Distance from offset center (for pupil)
  float dist = length(uv - pupilOffset);

  // Polar coordinates from center
  vec2 polar = toPolar(uv);
  float r = polar.x;
  float angle = polar.y;

  // Animated noise for organic iris texture
  float t = uTime * 0.3;
  float irisNoise = fbm(vec2(angle * 3.0 + t * 0.7, r * 5.0 - t * 0.4));
  float irisNoise2 = fbm(vec2(angle * 5.0 - t * 0.5, r * 3.0 + t * 0.6));

  // Iris ring boundaries
  float innerRadius = uPupilSize * 0.5;
  float outerRadius = innerRadius + uIrisWidth;

  // Smooth pupil edge
  float pupilMask = 1.0 - smoothstep(innerRadius - 0.02, innerRadius + 0.02, dist);

  // Iris band
  float irisMask = smoothstep(innerRadius - 0.01, innerRadius + 0.03, dist)
                 * (1.0 - smoothstep(outerRadius - 0.03, outerRadius + 0.01, dist));

  // Warp the iris with noise for organic look
  float warpedIris = irisMask * (0.6 + 0.4 * irisNoise);

  // Chromatic iris: violet on inner edge, cyan on outer edge
  float irisPosition = smoothstep(innerRadius, outerRadius, dist);
  vec3 irisColor = mix(uColor, uAccentColor, irisPosition * irisPosition);

  // Add swirling noise bands to iris
  float bands = sin(angle * 12.0 + irisNoise2 * 6.0 + t * 2.0) * 0.5 + 0.5;
  irisColor += bands * 0.15 * uIntensity;

  // Nebula tendrils radiating outward
  float tendrils = fbm(vec2(angle * 2.0 + t * 0.2, r * 8.0 - t * 0.3));
  float tendrilMask = smoothstep(outerRadius - 0.05, outerRadius + 0.15, dist)
                    * (1.0 - smoothstep(outerRadius + 0.05, outerRadius + 0.35, dist));
  vec3 tendrilColor = mix(uAccentColor, uColor, tendrils) * tendrilMask * tendrils * 0.6 * uIntensity;

  // Outer corona / glow
  float corona = exp(-dist * 2.5) * uGlowIntensity;
  float coronaPulse = 1.0 + 0.15 * sin(uTime * 1.5);
  vec3 coronaColor = mix(uColor, uAccentColor, 0.5) * corona * coronaPulse;

  // Chromatic aberration fringe at iris edge
  float fringeR = smoothstep(outerRadius - 0.04, outerRadius, dist)
                * (1.0 - smoothstep(outerRadius, outerRadius + 0.04, dist));
  vec3 fringe = vec3(0.3, 0.1, 0.5) * fringeR * 0.8 * uIntensity;

  // Compose final color
  vec3 bgColor = vec3(0.02, 0.01, 0.04);
  vec3 col = bgColor;

  // Add corona glow
  col += coronaColor;

  // Add tendrils
  col += tendrilColor;

  // Add iris
  col += irisColor * warpedIris * uIntensity;

  // Add chromatic fringe
  col += fringe;

  // Draw pupil (deep black)
  col = mix(col, vec3(0.0, 0.0, 0.005), pupilMask);

  // Pupil highlight (tiny specular dot)
  float highlight = smoothstep(0.06, 0.02, length(uv - pupilOffset + vec2(0.06, 0.06)));
  col += vec3(0.6, 0.7, 1.0) * highlight * 0.5;

  // Vignette
  float vignette = 1.0 - smoothstep(0.5, 1.5, r);
  col *= vignette;

  gl_FragColor = vec4(col, 1.0);
}
`;

export function CosmicEye({
  color = "#8b5cf6",
  accentColor = "#22d3ee",
  intensity = 1.5,
  pupilSize = 0.55,
  irisWidth = 0.25,
  glowIntensity = 0.4,
  scale = 0.85,
  noiseScale = 1.0,
  pupilFollow = 1.0,
  speed = 1.0,
  className,
}: CosmicEyeProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mounted, setMounted] = useState(false);

  // Store mutable state in refs to avoid re-running effect
  const mouseRef = useRef({ x: 0, y: 0 });
  const smoothMouseRef = useRef({ x: 0, y: 0 });

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (!mounted) return;
    const container = containerRef.current;
    if (!container) return;

    let animFrameId: number;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    let glContext: any = null;

    // Dynamic import of ogl to avoid SSR issues
    import("ogl").then(({ Renderer, Program, Mesh, Triangle, Texture }) => {
      if (!container) return;

      const renderer = new Renderer({
        dpr: Math.min(window.devicePixelRatio, 2),
        alpha: false,
      });
      const gl = renderer.gl;
      glContext = gl;
      container.appendChild(gl.canvas as HTMLCanvasElement);
      gl.clearColor(0.02, 0.01, 0.04, 1);

      // Generate noise texture (deterministic)
      const noiseSize = 256;
      const noiseData = new Uint8Array(noiseSize * noiseSize * 4);
      for (let i = 0; i < noiseSize * noiseSize; i++) {
        const v = Math.floor(seededRandom(i + 1) * 256);
        noiseData[i * 4 + 0] = v;
        noiseData[i * 4 + 1] = v;
        noiseData[i * 4 + 2] = v;
        noiseData[i * 4 + 3] = 255;
      }

      const noiseTex = new Texture(gl, {
        image: noiseData,
        width: noiseSize,
        height: noiseSize,
        wrapS: gl.REPEAT,
        wrapT: gl.REPEAT,
      });

      // Parse hex colors to vec3
      function hexToVec3(hex: string): [number, number, number] {
        const h = hex.replace("#", "");
        return [
          parseInt(h.substring(0, 2), 16) / 255,
          parseInt(h.substring(2, 4), 16) / 255,
          parseInt(h.substring(4, 6), 16) / 255,
        ];
      }

      const geometry = new Triangle(gl);

      const program = new Program(gl, {
        vertex: VERTEX_SHADER,
        fragment: FRAGMENT_SHADER,
        uniforms: {
          uTime: { value: 0 },
          uAspect: { value: 1 },
          uMouse: { value: [0, 0] },
          uColor: { value: hexToVec3(color) },
          uAccentColor: { value: hexToVec3(accentColor) },
          uIntensity: { value: intensity },
          uPupilSize: { value: pupilSize },
          uIrisWidth: { value: irisWidth },
          uGlowIntensity: { value: glowIntensity },
          uScale: { value: scale },
          uNoiseScale: { value: noiseScale },
          uPupilFollow: { value: pupilFollow },
          uNoiseTex: { value: noiseTex },
        },
      });

      const mesh = new Mesh(gl, {
        geometry,
        program,
      });

      // Resize handler
      function resize() {
        if (!container) return;
        const w = container.clientWidth;
        const h = container.clientHeight;
        renderer.setSize(w, h);
        program.uniforms.uAspect.value = w / h;
      }

      resize();
      window.addEventListener("resize", resize);

      // Mouse handlers
      const onMouseMove = (e: MouseEvent) => {
        const rect = container.getBoundingClientRect();
        mouseRef.current.x =
          ((e.clientX - rect.left) / rect.width) * 2 - 1;
        mouseRef.current.y =
          -(((e.clientY - rect.top) / rect.height) * 2 - 1);
      };

      const onMouseLeave = () => {
        mouseRef.current.x = 0;
        mouseRef.current.y = 0;
      };

      container.addEventListener("mousemove", onMouseMove);
      container.addEventListener("mouseleave", onMouseLeave);

      // Animation loop
      const startTime = performance.now();

      function animate() {
        animFrameId = requestAnimationFrame(animate);

        // Smooth mouse lerp
        const lerpFactor = 0.05;
        smoothMouseRef.current.x +=
          (mouseRef.current.x - smoothMouseRef.current.x) * lerpFactor;
        smoothMouseRef.current.y +=
          (mouseRef.current.y - smoothMouseRef.current.y) * lerpFactor;

        const elapsed = (performance.now() - startTime) / 1000;
        program.uniforms.uTime.value = elapsed * speed;
        program.uniforms.uMouse.value = [
          smoothMouseRef.current.x,
          smoothMouseRef.current.y,
        ];

        renderer.render({ scene: mesh });
      }

      animate();

      // Cleanup stored for unmount
      (container as HTMLDivElement & { _ceCleanup?: () => void })._ceCleanup = () => {
        cancelAnimationFrame(animFrameId);
        window.removeEventListener("resize", resize);
        container.removeEventListener("mousemove", onMouseMove);
        container.removeEventListener("mouseleave", onMouseLeave);
        const canvas = gl.canvas as HTMLCanvasElement;
        if (canvas && container.contains(canvas)) {
          container.removeChild(canvas);
        }
        const ext = gl.getExtension("WEBGL_lose_context");
        if (ext) ext.loseContext();
      };
    });

    return () => {
      cancelAnimationFrame(animFrameId);
      const cleanup = (container as HTMLDivElement & { _ceCleanup?: () => void })._ceCleanup;
      if (cleanup) cleanup();
    };
  }, [
    mounted,
    color,
    accentColor,
    intensity,
    pupilSize,
    irisWidth,
    glowIntensity,
    scale,
    noiseScale,
    pupilFollow,
    speed,
  ]);

  if (!mounted) {
    return (
      <div
        className={cn(
          "relative w-full h-full min-h-[200px] bg-[#050114]",
          className
        )}
      />
    );
  }

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative w-full h-full min-h-[200px] overflow-hidden bg-[#050114]",
        className
      )}
      style={{ touchAction: "none" }}
    />
  );
}
